.mes-header {
    display: flex;
    align-items: center;
    gap: 10px;
}

.ano-header::after,
.mes-header::after {
    content: "▶";
    font-size: 0.9rem;
    transition: transform 0.25s ease;
}

.ano-header.open::after,
.mes-header.open::after {
    transform: rotate(90deg);
}

.ano-header.open,
.mes-header.open {
    color: var(--cor-principal);
}

.botoes {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 10px;
    width: 100%;
}

#escondido {
    display: none;
}

