.cfg-field input:not(:placeholder-shown)+label {
    top: -1px;
    font-size: 12px;
    color: var(--cor-principal);
}

/* Seta do select */
.cfg-field:has(select)::after {
    content: "▾";
    position: absolute;
    right: 16px;
    top: 50%;
    transform: translateY(-50%);
    color: var(--cor-principal);
    pointer-events: none;
    font-size: 0.9rem;
    z-index: 1;
}

.cfg-field select,
.cfg-field input[type="text"],
.cfg-field input[type="number"],
.cfg-field input[type="date"] {
    height: 58px;
    border-radius: 10px;
    border: 2px solid var(--cor-principal);
    padding: 0 18px;
    font-size: 17px;
    color: var(--cor-principal);
    background: transparent;
    font-weight: 600;
    width: 100%;
    appearance: none;
    transition: border-color 0.2s ease-in-out;
}

.cfg-field select:focus,
.cfg-field input:focus {
    outline: none;
    border-color: var(--cor-hover);
    transition: border-color 0.2s ease-in-out;
}

/* Row of fields */
.cfg-row {
    display: flex;
    flex-wrap: wrap;
    gap: 20px;
    align-items: flex-end;
}

.cfg-row .cfg-field {
    flex: 1;
    min-width: 180px;
    max-width: 300px;
}

.cfg-row .cfg-btn {
    align-self: flex-end;
}

/* Two-column layout (form + checkboxes) */
.cfg-split {
    display: flex;
    flex-wrap: wrap;
    gap: 32px;
    align-items: flex-start;
}

.cfg-split-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 24px;
    min-width: 260px;
}

.cfg-split-side {
    display: flex;
    flex-direction: column;
    gap: 20px;
    min-width: 240px;
}

/* Checkboxes */
.cfg-check-label {
    display: flex;
    align-items: center;
    gap: 14px;
    font-size: 17px;
    font-weight: 600;
    color: var(--cor-texto-principal);
    cursor: pointer;
}

.cfg-check-label input[type="checkbox"] {
    width: 22px;
    height: 22px;
    accent-color: var(--cor-principal);
    cursor: pointer;
    flex-shrink: 0;
}

.cfg-switch-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    padding: 8px 0;
}

.cfg-switch-text {
    font-size: 16px;
    font-weight: 600;
    color: var(--cor-texto-principal);
}

.cfg-switch {
    position: relative;
    width: 54px;
    height: 30px;
    flex-shrink: 0;
}

.cfg-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.cfg-switch-slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background: var(--cor-toggle-inativo);
    border-radius: 999px;
    transition: .2s;
}

.cfg-switch-slider:before {
    content: "";
    position: absolute;
    height: 24px;
    width: 24px;
    left: 3px;
    top: 3px;
    background: var(--cor-fundo-card);
    border-radius: 50%;
    transition: .2s;
    box-shadow: 0 1px 3px var(--sombra-caixa);
}

.cfg-switch input:checked+.cfg-switch-slider {
    background: var(--cor-principal);
}

.cfg-switch input:checked+.cfg-switch-slider:before {
    transform: translateX(24px);
}

/* Buttons */
.cfg-btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    height: 52px;
    padding: 0 24px;
    min-width: 130px;
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border: none;
    border-radius: 10px;
    font-size: 17px;
    font-weight: 400;
    cursor: pointer;
    transition: background 0.2s;
    align-self: flex-start;
    margin: 0;
}

.cfg-btn:hover {
    background: var(--cor-hover);
}

.cfg-btn.danger {
    background: var(--red-700);
}

.cfg-btn.danger:hover {
    background: var(--red-800);
}

/* Fix: .containerGeral button (especificidade 11) sobrescreve .cfg-btn (10).
           Esta regra tem especificidade 21 e restaura padding/margin corretos. */
.cfg-page button.cfg-btn {
    padding: 0 24px;
    margin: 0;
    height: 52px;
}

/* List container */
.cfg-list-box {
    border-radius: 15px;
    border: 2px solid var(--cor-principal);
    overflow: hidden;
}

.cfg-list-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 18px;
    border-bottom: 1px solid var(--cor-tinte-borda);
    font-size: 16px;
}

.cfg-list-item:last-child {
    border-bottom: none;
}

.cfg-list-item .cfg-btn.danger {
    height: 38px;
    min-width: 38px;
    padding: 0 12px;
    font-size: 15px;
}

.cfg-delete-label {
    font-size: 17px;
    font-weight: 600;
    color: var(--cor-texto-principal);
}

/* Table inside cards */
.tabela-config {
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
}

.cfg-table {
    width: 100%;
    border-collapse: separate;
    border-radius: 15px;
    overflow: hidden;
    border-spacing: 0;
    border: 2px solid var(--cor-principal);
}

.cfg-table th {
    text-align: left;
    padding: 12px 18px;
    font-size: 0.95rem;
    font-weight: 600;
    color: var(--cor-principal);
    border-bottom: 1px solid var(--cor-tinte-borda);
    background: var(--cor-fundo-pagina);
}

.cfg-table td {
    padding: 12px 18px;
    font-size: 0.95rem;
    color: var(--cor-principal);
    border-bottom: 1px solid var(--cor-tinte-borda);
}

.cfg-table tr:last-child td {
    border-bottom: none;
}

.cfg-table-empty td {
    text-align: center;
    color: var(--cor-texto-secundario);
    font-style: italic;
}

.btn-downDados button {
    display: flex;
    flex-direction: column;
}

@import "root.css"; 

/* ── Agenda page ── */

/* Two-column layout */
.ag-layout {
    display: flex;
    gap: 24px;
    align-items: flex-start;
}

/* ── Calendar panel ── */
.ag-cal-panel {
    flex: 1 1 0;
    min-width: 0;
}

/* Month navigation */
.ag-month-nav {
    display: flex;
    align-items: center;
    gap: 20px;
    margin-bottom: 16px;
}

.ag-month-name {
    color: var(--cor-titulo);
    font-size: 2.5rem;
    font-weight: 500;
    min-width: 220px;
}

.ag-nav-btn {
    background: var(--cor-principal);
    color: #fff;
    border: none;
    border-radius: 8px;
    width: 38px;
    height: 38px;
    font-size: 1.3rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.2s;
    margin: 0;
    padding: 0;
}

.ag-nav-btn:hover {
    background: var(--cor-hover);
}

/* Day-of-week header */
.ag-weekdays {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 6px;
    margin-bottom: 6px;
}

.ag-weekday {
    text-align: center;
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--cor-principal);
    padding: 4px 0;
}

/* Calendar grid */
.ag-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 6px;
}

/* Single day cell */
.ag-day {
    background: var(--cor-principal);
    border-radius: 10px;
    box-shadow: 0px 4px 4px rgba(0, 0, 0, 0.25);
    padding: 10px 8px 6px;
    min-height: 80px;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    transition: background 0.15s, transform 0.1s;
    user-select: none;
}

.ag-day:hover {
    background: var(--cor-hover);
    transform: translateY(-2px);
}

.ag-day.ag-today {
    outline: 2px solid var(--cor-hover);
    outline-offset: -2px;
}

.ag-day.ag-selected {
    background: var(--cor-hover);
}

.ag-day.ag-empty {
    background: transparent;
    box-shadow: none;
    cursor: default;
    pointer-events: none;
}

.ag-day-num {
    color: #fff;
    font-size: 1.4rem;
    font-weight: 400;
    line-height: 1;
}

/* Colored dots */
.ag-dots {
    display: flex;
    flex-wrap: wrap;
    gap: 3px;
    margin-top: 4px;
}

.ag-dot {
    width: 10px;
    height: 10px;
    border-radius: 9999px;
    flex-shrink: 0;
}

.ag-dot-gasto {
    background: #FF9E9E;
}

.ag-dot-recebimento {
    background: #B7FFB6;
}

.ag-dot-transferencia {
    background: #7FFFFF;
}

.ag-dot-agendamento {
    background: #FFFF9E;
}

/* ── Summary panel ── */
.ag-resumo {
    width: 340px;
    flex-shrink: 0;
    background: #FAFFFF;
    border-radius: 30px;
    box-shadow: 0px 4px 4px rgba(0, 0, 0, 0.25);
    padding: 24px 20px;
    display: flex;
    flex-direction: column;
    gap: 16px;
    max-height: calc(100vh - 120px);
    overflow-y: auto;
    position: sticky;
    top: 20px;
}

.ag-resumo-titulo {
    color: var(--cor-titulo);
    font-size: 2rem;
    font-weight: 400;
    border-bottom: 2px solid var(--cor-principal);
    padding-bottom: 10px;
}

.ag-resumo-empty {
    color: #888;
    font-size: 1rem;
    text-align: center;
    padding: 20px 0;
}

/* Event group date header */
.ag-resumo-data {
    color: #1A1A1A;
    font-size: 1.2rem;
    font-weight: 400;
    margin-top: 8px;
}

/* Event chip */
.ag-evento {
    border-radius: 10px;
    padding: 10px 14px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 10px;
}

.ag-evento-titulo {
    font-size: 1rem;
    font-weight: 400;
}

.ag-evento-valor {
    font-size: 0.95rem;
    font-weight: 400;
    white-space: nowrap;
}

.ag-evento.gasto {
    background: #FF9E9E;
    color: #A00000;
}

.ag-evento.recebimento {
    background: #B7FFB6;
    color: #0A6000;
}

.ag-evento.transferencia {
    background: #7FFFFF;
    color: #006C9E;
}

.ag-evento.agendamento {
    background: #FFFF9E;
    color: #AFA900;
}

