    padding: 4px 0;
    max-height: 235px;
    overflow: auto;
    background: transparent;
}

.fr-box::-webkit-scrollbar {
    width: 10px;
}

.fr-box::-webkit-scrollbar-thumb {
    background: var(--cor-hover);
    border-radius: 8px;
    border: 2px solid var(--cor-fundo-card);
}

.fr-grid-2 {
    display: flex;
    flex-direction: column;
    gap: 18px;
}

.fr-lista {
    display: flex;
    flex-direction: row;
    gap: 8px;
}

.fr-check {
    display: flex;
    align-items: center;
    gap: 10px;
    font-size: 1rem;
    color: var(--cor-texto-principal);
    padding: 6px 8px;
    border-radius: 8px;
    transition: background .15s;
}

.fr-check:hover {
    background: var(--cor-hover);
}

.fr-check input {
    width: 18px;
    height: 18px;
    accent-color: var(--cor-principal);
    border-color: var(--cor-principal);
}

.fr-date-row {
    display: flex;
    align-items: center;
    gap: 12px;
    flex-wrap: wrap;
}

.fr-date-display {
    font-size: 1rem;
    font-weight: 700;
    color: var(--cor-titulo);
    margin: 0;
    padding: 10px 12px;
    background: var(--cor-fundo-inativo);
    border: 1px solid var(--cor-tinte-borda);
    border-radius: 10px;
}

.fr-btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    height: 50px;
    padding: 0 18px;
    border-radius: 10px;
    font-size: 1rem;
    font-weight: 700;
    cursor: pointer;
    transition: .2s;
}

.fr-btn.primary {
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border: none;
    box-shadow: 0 6px 18px var(--cor-tinte-borda);
}

.fr-btn.primary:hover {
    background: var(--cor-hover);
}

.fr-btn.secondary {
    background: transparent;
    color: var(--cor-principal);
    border: 2px solid var(--cor-principal);
}

.fr-btn.secondary:hover {
    background: var(--cor-tinte-suave);
}

.fr-actions {
    display: flex;
    justify-content: flex-end;
    gap: 10px;
}

.fr-busca-grid {
    display: flex;
    gap: 12px;
    align-items: end;
}

.fr-busca-grow {
    flex: 1;
    min-width: 220px;
}

.fr-select-wrap {
    position: relative;
}

.fr-select-wrap::after {
    content: '▾';
    position: absolute;
    right: 14px;
    top: 50%;
    transform: translateY(-44%);
    color: var(--cor-principal);
    pointer-events: none;
    font-size: .9rem;
}

.fr-select {
    width: 100%;
    height: 58px;
    border-radius: 10px;
    border: 2px solid var(--cor-principal);
    padding: 0 38px 0 14px;
    font-size: 1rem;
    font-weight: 600;
    color: var(--cor-principal);
    background: var(--cor-fundo-card);
    appearance: none;
    outline: none;
    transition: border-color .2s, box-shadow .2s;
}

.fr-select:focus {
    border-color: var(--cor-hover);
    box-shadow: 0 0 0 3px var(--cor-tinte-medio);
}



@media (max-width: 760px) {
    .fr-card {
        width: 96vw;
        padding: 16px;
        border-radius: 20px;
        gap: 16px;
    }

    .fr-title {
        font-size: 1.45rem;
    }

    .fr-busca-grid {
        width: 100%;
        flex-direction: column;
        align-items: stretch;
    }

    .fr-box {
        max-height: 190px;
    }

    .fr-actions {
        flex-direction: column-reverse;
    }

    .fr-actions .fr-btn {
        width: 100%;
    }

    .fr-date-row {
        align-items: stretch;
    }
}

@import "root.css";

/* ── Meu Perfil page ── */

/* ── Shared card ── */
.pf-card {
    background: var(--cor-fundo-card);
    border-radius: 30px;
    box-shadow: 0px 4px 4px rgba(0, 0, 0, 0.25);
    padding: 28px 24px;
    margin-bottom: 28px;
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.pf-card h2 {
    color: var(--cor-titulo);
    font-size: 2rem;
    font-weight: 700;
    margin: 0;
}

/* ── Profile hero ── */
.pf-hero {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 18px;
    margin-bottom: 8px;
}

/* Avatar circle */
.pf-avatar {
    width: 200px;
    height: 200px;
    border-radius: 9999px;
    border: 2px solid var(--cor-principal);
    background: #FAFFFF;
    box-shadow: 0px 4px 4px rgba(0, 0, 0, 0.25);
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
}

.pf-avatar i {
    font-size: 5rem;
    color: var(--cor-principal);
}

/* XP bar */
.pf-xp-wrap {
    width: 320px;
    background: #FAFFFF;
    border-radius: 100px;
    box-shadow: 0px 2px 4px rgba(0, 0, 0, 0.15);
    height: 22px;
    display: flex;
    align-items: center;
    overflow: hidden;
    position: relative;
}

.pf-xp-bar {
    height: 100%;
    width: 30%;
    background: var(--cor-principal);
    border-radius: 100px;
    transition: width 0.4s ease;
}

.pf-xp-label {
    position: absolute;
    right: 12px;
    font-size: 11px;
    color: var(--cor-texto-secundario);
    font-weight: 200;
}

/* Name row */
.pf-nome-row {
    display: flex;
    align-items: flex-end;
    gap: 12px;
}

.pf-nome {
    color: var(--cor-titulo);
    font-size: 2.2rem;
    font-weight: 600;
    text-align: center;
    line-height: 1.15;
}

.pf-edit-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px;
    margin: 0;
    color: #367373;
    font-size: 1.5rem;
    line-height: 1;
    display: flex;
    align-items: center;
}

/* Info row */
.pf-info-row {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: 24px;
}

.pf-info-item {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 1rem;
}

.pf-info-item strong {
    font-weight: 700;
    color: var(--cor-texto-principal);
}

.pf-info-item span {
    font-weight: 500;
    color: var(--cor-texto-principal);
}

/* ── Temas ── */
.pf-temas-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 24px;
    align-items: flex-end;
}

.pf-tema-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
    cursor: pointer;
}

.pf-tema-swatch {
    width: 56px;
    height: 56px;
    border-radius: 50px;
    transition: border-color 0.2s, transform 0.15s;
}

.pf-tema-item:hover .pf-tema-swatch {
    transform: scale(1.1);
}

.pf-tema-item.ativo .pf-tema-swatch {
    border: 3px solid var(--cor-para-destacar);
}

.pf-tema-label {
    font-size: 0.85rem;
    font-weight: 600;
    color: var(--cor-texto-principal);
    text-align: center;
}
/* Toggles */
.pf-toggles {
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.pf-toggle-row {
    display: flex;
    align-items: center;
    gap: 14px;
    font-size: 1rem;
    font-weight: 400;
    color: var(--cor-texto-principal);
}

.pf-toggle {
    position: relative;
    width: 44px;
    height: 22px;
    flex-shrink: 0;
}

.pf-toggle input {
    opacity: 0;
    width: 0;
    height: 0;
}

.pf-toggle-slider {
    position: absolute;
    inset: 0;
    background: #d1d5db;
    border-radius: 12px;
    cursor: pointer;
    transition: background 0.2s;
    /* outline: 1px solid #535353; */
}

.pf-toggle-slider::after {
    content: "";
    position: absolute;
    width: 18px;
    height: 18px;
    top: 2px;
    left: 2px;
    background: #535353;
    border-radius: 12px;
    transition: transform 0.2s;
}

.pf-toggle input:checked+.pf-toggle-slider {
    background: #EBF4F4;
    outline-color: var(--cor-principal);
}

.pf-toggle input:checked+.pf-toggle-slider::after {
    background: var(--cor-principal);
    transform: translateX(22px);
}

.pf-toggle-state {
    font-size: 0.7rem;
    font-weight: 400;
    color: var(--cor-texto-principal);
    min-width: 24px;
}

/* ── Shared btn (same as cfg-btn) ── */
.pf-btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    height: 52px;
    padding: 0 24px;
    min-width: 130px;
    background: var(--cor-principal);
    color: #fff;
    border: none;
    border-radius: 10px;
    font-size: 17px;
    font-weight: 400;
    cursor: pointer;
    transition: background 0.2s;
    align-self: flex-start;
    margin: 0;
}

.pf-btn:hover {
    background: var(--cor-hover);
}

.pf-btn.danger {
    background: #e53e3e;
}

.pf-btn.danger:hover {
    background: #c53030;
}

/* ── Resumo de Configurações ── */
.pf-resumo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 8px 24px;
}

.pf-resumo-item {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.pf-resumo-label {
    font-size: 1rem;
    font-weight: 600;
    color: var(--cor-texto-principal);
}

.pf-resumo-valor {
    font-size: 1rem;
    font-weight: 400;
    color: var(--cor-texto-principal);
}

/* ── Tables (institutions / categories) ── */
.pf-table {
    width: 100%;
    border-collapse: collapse;
    border-radius: 15px;
    overflow: hidden;
    outline: 2px solid var(--cor-principal);
}

.pf-table th {
    background: transparent;
    text-align: left;
    padding: 12px 16px;
    font-size: 1rem;
    font-weight: 600;
    color: var(--cor-texto-principal);
    border-bottom: 1px solid var(--cor-principal);
}

.pf-table td {
    padding: 12px 16px;
    font-size: 0.95rem;
    color: #0E5454;
    border-bottom: 1px solid rgba(54, 115, 115, 0.2);
    vertical-align: middle;
}

.pf-table tr:last-child td {
    border-bottom: none;
}

.pf-table-actions {
    display: flex;
    gap: 8px;
    align-items: center;
}

.pf-icon-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px;
    margin: 0;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s;
    font-size: 1.2rem;
}

.pf-icon-btn.edit {
    color: #00BBDD;
}

.pf-icon-btn.edit:hover {
    background: rgba(0, 187, 221, 0.1);
}

.pf-icon-btn.delete {   
    color: #e53e3e;
}

.pf-icon-btn.delete:hover {
    background: rgba(229, 62, 62, 0.1);
}

.pf-campo {
    display: flex;
    flex-direction: column;
}

.pf-campo label {
    margin-bottom: 20px;
}

.pf-campo input {
    border: 1px solid var(--cor-principal);
    padding: 10px 20px;
    height: 50px;
    width: 500px;
    border-radius: 50px;
    outline: none;
}

.btn-criticos .btn-urgente {
    background-color: var(--red-700);
    padding: 15px;
    margin: 0 10px;
}

