:root {
    --cor-principal: #367373;
    --cor-fundo-pagina: #EBF4F4;
    --cor-fundo-card: #FAFFFF;
    --cor-titulo: #004C58;
    --cor-hover: #B4D9D5;
    --cor-texto-principal: #1A1A1A;
    --cor-texto-secundario: #4A4A4A;
    --cor-texto-alternativo: #367373;
    --cor-texto-claro: #FFFFFF;
    --cor-para-destacar: #004C58;
    --sombra-card: rgba(54, 115, 115, 0.099);
    --red-700: #b91c1c;
    --red-100: #fee2e2;
    --green-700: #15803d;
    --green-100: #d1fae5;
}

body[data-tema="padrao"][data-mode="light"] {
    --cor-principal: #367373;
    --cor-fundo-pagina: #EBF4F4;
    --cor-fundo-card: #FAFFFF;
    --cor-titulo: #004C58;
    --cor-hover: #B4D9D5;
    --cor-texto-principal: #1A1A1A;
    --cor-texto-secundario: #4A4A4A;
    --cor-texto-alternativo: #367373;
    --cor-texto-claro: #FFFFFF;
    --cor-para-destacar: #004C58;
    --sombra-card: rgba(54, 115, 115, 0.099);
    --red-700: #b91c1c;
    --red-100: #fee2e2;
    --green-700: #15803d;
    --green-100: #d1fae5;
}

body[data-tema="padrao"][data-mode="dark"] {
    --cor-principal: #096464;
    --cor-fundo-pagina: #041A1A;
    --cor-fundo-card: #011D1D;
    --cor-titulo: #00B2CE;
    --cor-hover: #B4D9D5;
    --cor-texto-principal: #FFFFFF;
    --cor-texto-secundario: #94a3b8;
    --cor-texto-alternativo: #7dd3fc;
